export const getUser = () => {
  const userStr = sessionStorage.getItem('user')
  return userStr ? JSON.parse(userStr) : null
}

export const getStudentDetails = () => {
  const studentDetails = sessionStorage.getItem('studentDetails')
  return studentDetails ? JSON.parse(studentDetails) : null
}

export const getToken = () => {
  return sessionStorage.getItem('token') || null
}

export const setUserSession = (token, user, studentDetails) => {
  sessionStorage.setItem('token', token)
  sessionStorage.setItem('user', JSON.stringify(user))
  sessionStorage.setItem('studentDetails', JSON.stringify(studentDetails))
}

export const removeUserSession = () => {
  sessionStorage.removeItem('token')
  sessionStorage.removeItem('user')
  sessionStorage.removeItem('studentDetails')
}
